msg.query = `
from(bucket: "irrigation")
  |> range(start: 0)
  |> filter(fn: (r) => r._measurement == "sensors")
  |> pivot(rowKey: ["_time"], columnKey: ["_field"], valueColumn: "_value")
  |> sort(columns: ["_time"], desc: false)
`;
return msg;

const limit = Math.min(parseInt(msg.req.query.limit || '500', 10), 5000);

msg.payload = { ok: true, count: (msg.payload || []).length, data: msg.payload || [] };
msg.statusCode = 200;
msg.headers = { 'Content-Type': 'application/json', 'Access-Control-Allow-Origin': '*' };
return msg;

