// Reads rpi_status written by Tab 1 (vps_fn_rpi_status → flow.set)
const rpiStatus  = flow.get('rpi_status')  || 'unknown';
const lastEvent  = flow.get('last_event')  || null;
const lastTimer  = flow.get('last_timer')  || null;

msg.payload = {
    ok: true,
    data: {
        rpi:        rpiStatus,
        online:     rpiStatus === 'online',
        last_event: lastEvent,
        last_timer: lastTimer,
        server_time: new Date().toISOString()
    }
};
msg.statusCode = 200;
msg.headers = { 'Content-Type': 'application/json', 'Access-Control-Allow-Origin': '*' };
return msg;

msg.statusCode = 204;
msg.headers = {
    'Access-Control-Allow-Origin':  '*',
    'Access-Control-Allow-Methods': 'GET, OPTIONS',
    'Access-Control-Allow-Headers': 'Content-Type, Authorization',
    'Access-Control-Max-Age':       '86400'
};
msg.payload = '';
return msg;
